SELECT AVG(prenatal_visits) AS avg_visits
FROM prenatal_care
WHERE provider_id = 1;

SELECT COUNT(*) AS treatment_count
FROM treatment
WHERE treatment_type = 'antibiotics';

SELECT prenatal_visits
FROM prenatal_care
WHERE record_id = 1;

SELECT project_name
FROM research_projects
ORDER BY project_name;

SELECT prenatal_visits, prenatal_start
FROM prenatal_care
WHERE prenatal_id = 1;

SELECT treatment_type, MAX(treatment_end) AS latest_treatment_end
FROM treatment
GROUP BY treatment_type;

SELECT provider_id, COUNT(prenatal_id) AS num_prenatal_records
FROM prenatal_care
GROUP BY provider_id;

SELECT treatment_type
FROM treatment
WHERE treatment_type = 'antibiotics';
